pub fn from_syntax_component_kind(
    kind: &lightningcss::values::syntax::SyntaxComponentKind,
) -> KindSet {
    use lightningcss::values::syntax::SyntaxComponentKind;
    match kind {
        SyntaxComponentKind::Length => KindSet::LENGTH,
        SyntaxComponentKind::Number => KindSet::NUMBER,
        SyntaxComponentKind::Percentage => KindSet::PERCENTAGE,
        SyntaxComponentKind::Color => KindSet::COLOR,
        SyntaxComponentKind::Image => KindSet::IMAGE,
        SyntaxComponentKind::Url => KindSet::URL,
        SyntaxComponentKind::Integer => KindSet::INTEGER,
        SyntaxComponentKind::Angle => KindSet::ANGLE,
        SyntaxComponentKind::Time => KindSet::TIME,
        SyntaxComponentKind::Resolution => KindSet::RESOLUTION,
        SyntaxComponentKind::TransformFunction => KindSet::TRANSFORM_FUNCTION,
        SyntaxComponentKind::TransformList => KindSet::TRANSFORM_LIST,
        // LengthPercentage maps to the composite LENGTH | PERCENTAGE
        SyntaxComponentKind::LengthPercentage => KindSet::LENGTH_PERCENTAGE,
        _ => KindSet::empty(),
    }
}

